const text = $input.first().json.content

const lines = text.trim().split('\n');
const now = new Date();
const upcomingBills = [];
const updatedBills = [];

for (const line of lines) {
  const match = line.match(/^(.+?)\s+(\d{1,2})\/(\d{1,2})\/(\d{2})\s+-\s+KSH\s+(.+)$/i);

  if (!match) continue;

  const name = match[1].trim();
  let day = parseInt(match[2]);
  let month = parseInt(match[3]) - 1; // JS months are 0-based
  let year = 2000 + parseInt(match[4]);
  const amount = match[5].trim();

  let billDate = new Date(year, month, day);

  // If the bill date has passed, roll to next month
  if (billDate < now) {
    billDate.setMonth(billDate.getMonth() + 1);
  }

  // Check if bill is within the next 7 days
  const diffDays = (billDate - now) / (1000 * 60 * 60 * 24);
  if (diffDays <= 7 && diffDays >= 0) {
    upcomingBills.push({ name, date: billDate.toDateString(), amount });
  }
  const formatter = new Intl.DateTimeFormat('en-GB', {
    day: '2-digit',
    month: '2-digit',
    year: '2-digit'
});

  updatedBills.push({ name, date: formatter.format(billDate), amount });
}
const allbills = updatedBills.map((item) => `${item.name} ${item.date} - KSH ${item.amount}`)
return [
  {
    json: {
      upcomingBills,
      updatedBills: allbills.join('\n')
    }
  }
];
